module RefModule(clk, rst, en, count);
    input clk;
    input rst;
    input en;
    output reg [7:0] count;
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (rst)
            count <= 8'b0;
        else if (en)
            count <= count + 1;
    end
endmodule
